function formatDistance(km: number): string {
  const miles = km * 0.621371;
  return miles < 10
    ? `${miles.toFixed(1)} mi away`
    : `${Math.round(miles)} mi away`;
}

const NEW_THRESHOLD_MS = 30 * 24 * 60 * 60 * 1000;

interface StoreCardProps {
  store: Store;
  /** Compact variant uses smaller text — used on homepage featured grid */
  compact?: boolean;
}

export function StoreCard({ store: s, compact = false }: StoreCardProps) {
  const isNew =
    Date.now() - new Date(s.created_at).getTime() < NEW_THRESHOLD_MS;

  return (
    <Link
      href={`/stores/${s.id}`}
      className="lr-card lr-card-strong block overflow-hidden transition hover:-translate-y-0.5 hover:shadow-[0_22px_60px_rgba(38,28,10,0.14)]"
    >
      {s.image_url ? (
        <div className="relative aspect-[4/3] w-full">
          <Image
            src={s.image_url}
            alt={s.name}
            fill
            className="object-cover"
