 1→import { session } from "@/lib/session";
 2→
 3→function apiBaseUrl() {
 4→  return (
 5→    process.env.NEXT_PUBLIC_API_BASE_URL?.replace(/\/+$/, "") ||
 6→    "http://localhost:8080"
 7→  );
 8→}
 9→
10→export class SessionExpiredError extends Error {
11→  constructor() {
12→    super("Your session has expired. Redirecting to sign in...");
13→    this.name = "SessionExpiredError";
14→  }
15→}
16→
17→export type RequestJSONInit = RequestInit & {
18→  token?: string;
19→  // For GET requests, allow Next.js caching when desired.
20→  next?: { revalidate?: number };
21→};
22→
23→export async function requestJSON<T>(
24→  path: string,
25→  init: RequestJSONInit = {},
26→): Promise<T> {
27→  const headers = new Headers(init.headers);
28→  headers.set("Content-Type", "application/json");
29→  if (init.token) headers.set("Authorization", `Bearer ${init.token}`);
30→
31→  const method = (init.method ?? "GET").toUpperCase();
32→  const cache = method === "GET" && init.next ? "force-cache" : "no-store";
33→
34→  const res = await fetch(`${apiBaseUrl()}${path}`, {
35→    ...init,
36→    headers,
37→    cache,
38→  });
39→
40→  if (!res.ok) {
41→    const text = await res.text().catch(() => "");
42→
43→    if (res.status === 401 && typeof window !== "undefined") {
44→      const path = window.location.pathname;
45→      // Never redirect login/register pages — their 401s are login failures, not session expiry.
46→      const isAuthPage = /^\/(seller|buyer)\/(login|register|auth)/.test(path);
47→      if (!isAuthPage) {
48→        session.clearToken();
49→        let loginUrl: string | null = null;
50→        if (path.startsWith("/seller") || path.startsWith("/pickup/confirm")) {
51→          loginUrl = "/seller/login";
52→        } else if (path.startsWith("/buyer")) {
53→          loginUrl = "/buyer/login";
54→        }
55→        if (loginUrl) {
56→          const next = path + window.location.search;
57→          window.location.href = `${loginUrl}?expired=1&next=${encodeURIComponent(next)}`;
58→          throw new SessionExpiredError();
59→        }
60→      }
61→    }
62→
63→    throw new Error(`API ${res.status}: ${text || res.statusText}`);
64→  }
65→
66→  return (await res.json()) as T;
67→}
68→
69→export function getApiBaseUrlForDebug() {
70→  return apiBaseUrl();
71→}
