  useEffect(() => { document.title = "Sign in — LocalRoots"; }, []);
  useEffect(() => {
    if (session.getToken()) router.replace(redirectTo);
  }, [router, redirectTo]);
  useEffect(() => {
    if (searchParams.get("expired") === "1") {
      showToast({ kind: "error", message: "Your session has expired. Please sign in again." });
    }
  }, [searchParams, showToast]);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);

  async function onSubmit(e: FormEvent) {
    e.preventDefault();
    setSubmitting(true);
    setError(null);
    try {
      const res = await sellerApi.login(email, password);
      session.setToken(res.token);
      router.replace(redirectTo);
    } catch (err: unknown) {
      setError(friendlyErrorMessage(err));
    } finally {
      setSubmitting(false);
    }
  }

  async function handleGoogleCredential(idToken: string) {
