  3→import Link from "next/link";
  4→import { useParams, useRouter } from "next/navigation";
  5→import { useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
  6→import {
  7→  sellerApi,
  8→  type SellerOrder,
  9→  type SellerPayoutSummary,
 10→  type SellerPickupWindow,
 11→  type SellerSubscriptionPlan,
 12→  type SellerSubscription,
 13→} from "@/lib/seller-api";
 14→import { session } from "@/lib/session";
 15→import { useToast } from "@/components/toast";
 16→import { friendlyErrorMessage, parseApiError } from "@/lib/ui";
 17→import { ConfirmDialog } from "@/components/confirm-dialog";
 18→import { PickupWindowList } from "@/components/seller/pickup-window-list";
 19→import { SubscriptionPlanList } from "@/components/seller/subscription-plan-list";
 20→import { OrderList } from "@/components/seller/order-list";
 21→import { SubscriberList } from "@/components/seller/subscriber-list";
 22→
 23→export default function SellerStorePage() {
 24→  const params = useParams<{ storeId: string }>();
 25→  const storeId = params.storeId;
 26→  const router = useRouter();
 27→  const { showToast, clearToast } = useToast();
 28→
 29→  const [token, setToken] = useState<string | null>(null);
 30→  const [error, setError] = useState<string | null>(null);
 31→
 32→  const [windows, setWindows] = useState<SellerPickupWindow[] | null>(null);
 33→  const [orders, setOrders] = useState<SellerOrder[] | null>(null);
 34→  const [payoutSummary, setPayoutSummary] = useState<SellerPayoutSummary | null>(
 35→    null,
 36→  );
 37→  const [plans, setPlans] = useState<SellerSubscriptionPlan[] | null>(null);
 38→  const [subscriptions, setSubscriptions] = useState<SellerSubscription[] | null>(null);
 39→  const [busySubId, setBusySubId] = useState<string | null>(null);
 40→
 41→  const [selectedWindowId, setSelectedWindowId] = useState<string>("");
 42→  const [supportOpen, setSupportOpen] = useState(false);
 43→  const supportBtnRef = useRef<HTMLButtonElement | null>(null);
 44→  const supportPanelRef = useRef<HTMLDivElement | null>(null);
 45→  const [supportPos, setSupportPos] = useState<{ top: number; left: number } | null>(null);
 46→  const [pickupCodeByOrderId, setPickupCodeByOrderId] = useState<
 47→    Record<string, string>
 48→  >({});
 49→  const [generatingCycle, setGeneratingCycle] = useState(false);
 50→  const [busyOrderId, setBusyOrderId] = useState<string | null>(null);
 51→  const [togglingPlan, setTogglingPlan] = useState(false);
 52→  const [confirmAction, setConfirmAction] = useState<{
 53→    title: string;
 54→    message: string;
 55→    confirmLabel: string;
 56→    destructive: boolean;
 57→    action: () => void;
 58→  } | null>(null);
 59→
 60→  const selectedWindow = useMemo(() => {
 61→    if (!selectedWindowId) return null;
 62→    return (windows ?? []).find((w) => w.id === selectedWindowId) ?? null;
 63→  }, [windows, selectedWindowId]);
 64→
 65→  const siteOrigin = useMemo(() => {
 66→    if (typeof window === "undefined") return "";
 67→    return window.location.origin;
 68→  }, []);
 69→
 70→  // Redirect to setup if no live plan
 71→  useEffect(() => {
 72→    if (plans !== null && !plans.some((p) => p.is_live)) {
 73→      router.replace(`/seller/stores/${storeId}/setup`);
 74→    }
 75→  }, [plans, storeId, router]);
 76→
 77→  useEffect(() => {
 78→    const t = session.getToken();
 79→    if (!t) {
 80→      router.replace("/seller/login");
 81→      return;
 82→    }
 83→    setToken(t);
 84→  }, [router]);
 85→
 86→  useLayoutEffect(() => {
 87→    if (!supportOpen) return;
 88→
 89→    const update = () => {
 90→      const btn = supportBtnRef.current;
 91→      if (!btn) return;
 92→      const rect = btn.getBoundingClientRect();
 93→      const w = 288; // matches w-[18rem]
 94→      const pad = 10;
 95→      const left = Math.max(
 96→        pad,
 97→        Math.min(rect.right - w, window.innerWidth - w - pad),
 98→      );
 99→      const top = Math.min(rect.bottom + 10, window.innerHeight - 20);
100→      setSupportPos({ top, left });
101→    };
102→
103→    update();
104→    window.addEventListener("resize", update);
105→    window.addEventListener("scroll", update, true);
106→    return () => {
107→      window.removeEventListener("resize", update);
108→      window.removeEventListener("scroll", update, true);
109→    };
110→  }, [supportOpen]);
111→
112→  useEffect(() => {
113→    if (!supportOpen) return;
114→    const onDown = (e: MouseEvent) => {
115→      const t = e.target as Node | null;
116→      if (!t) return;
117→      if (supportBtnRef.current?.contains(t)) return;
118→      if (supportPanelRef.current?.contains(t)) return;
119→      setSupportOpen(false);
120→    };
121→    const onKey = (e: KeyboardEvent) => {
122→      if (e.key === "Escape") setSupportOpen(false);
123→    };
124→    window.addEventListener("mousedown", onDown);
125→    window.addEventListener("keydown", onKey);
126→    return () => {
127→      window.removeEventListener("mousedown", onDown);
128→      window.removeEventListener("keydown", onKey);
129→    };
130→  }, [supportOpen]);
131→
132→  async function refreshAll(t: string) {
133→    const [, ws, , sps, subs] = await Promise.all([
134→      sellerApi.listPickupLocations(t, storeId),
135→      sellerApi.listPickupWindows(t, storeId),
136→      sellerApi.listProducts(t, storeId),
137→      sellerApi.listSubscriptionPlans(t, storeId),
138→      sellerApi.listSubscriptions(t, storeId),
139→    ]);
140→    setWindows(ws);
141→    setPlans(sps);
142→    setSubscriptions(subs);
143→    setSelectedWindowId((prev) => {
144→      if (prev && ws.some((w) => w.id === prev)) return prev;
145→      return ws[0]?.id ?? "";
146→    });
147→  }
148→
149→  useEffect(() => {
150→    if (!token) return;
151→    setError(null);
152→    refreshAll(token).catch((e: unknown) => {
153→      const apiErr = parseApiError(e);
154→      if (apiErr && apiErr.status === 403) {
155→        showToast({ kind: "error", message: "You don\u2019t have access to that store." });
156→        router.replace("/seller");
157→        return;
158→      }
159→      if (apiErr && apiErr.status === 404) {
160→        showToast({ kind: "error", message: "Store not found." });
161→        router.replace("/seller");
162→        return;
163→      }
164→      setError(friendlyErrorMessage(e));
165→    });
166→    // eslint-disable-next-line react-hooks/exhaustive-deps
167→  }, [token, storeId]);
168→
169→  useEffect(() => {
170→    if (!token || !selectedWindowId) return;
171→    setError(null);
