 21→// TestPickupConfirmPreview_Validation tests that the Preview handler
 22→// rejects requests with missing or malformed query params.
 23→func TestPickupConfirmPreview_Validation(t *testing.T) {
 24→	api := PickupConfirmAPI{} // nil DB triggers panic on real queries — we test early returns only.
 25→
 26→	cases := []struct {
 27→		name   string
 28→		query  string
 29→		status int
 30→	}{
 31→		{"missing both params", "", http.StatusBadRequest},
 32→		{"missing code", "?order=00000000-0000-0000-0000-000000000001", http.StatusBadRequest},
 33→		{"missing order", "?code=123456", http.StatusBadRequest},
 34→		{"invalid order uuid", "?order=not-a-uuid&code=123456", http.StatusBadRequest},
 35→	}
 36→
 37→	for _, tc := range cases {
 38→		t.Run(tc.name, func(t *testing.T) {
 39→			req := httptest.NewRequest(http.MethodGet, "/v1/seller/pickup/preview"+tc.query, nil)
 40→			rr := httptest.NewRecorder()
 41→			api.Preview(rr, req, AuthUser{ID: "user-1", Role: "seller"})
 42→			if rr.Code != tc.status {
 43→				t.Errorf("got %d want %d: %s", rr.Code, tc.status, rr.Body.String())
 44→			}
 45→		})
 46→	}
 47→}
 48→
 49→// TestPickupConfirmConfirm_Validation tests that the Confirm handler
 50→// rejects requests with missing or malformed body fields.
 51→func TestPickupConfirmConfirm_Validation(t *testing.T) {
 52→	api := PickupConfirmAPI{}
 53→
 54→	cases := []struct {
 55→		name   string
 56→		body   map[string]any
 57→		status int
 58→	}{
 59→		{"empty body", map[string]any{}, http.StatusBadRequest},
 60→		{"missing pickup_code", map[string]any{"order_id": "00000000-0000-0000-0000-000000000001"}, http.StatusBadRequest},
 61→		{"missing order_id", map[string]any{"pickup_code": "123456"}, http.StatusBadRequest},
 62→		{"invalid order_id", map[string]any{"order_id": "bad", "pickup_code": "123456"}, http.StatusBadRequest},
 63→	}
 64→
 65→	for _, tc := range cases {
 66→		t.Run(tc.name, func(t *testing.T) {
 67→			b, _ := json.Marshal(tc.body)
 68→			req := httptest.NewRequest(http.MethodPost, "/v1/seller/pickup/confirm", bytes.NewReader(b))
 69→			req.Header.Set("Content-Type", "application/json")
 70→			rr := httptest.NewRecorder()
 71→			api.Confirm(rr, req, AuthUser{ID: "user-1", Role: "seller"})
 72→			if rr.Code != tc.status {
 73→				t.Errorf("got %d want %d: %s", rr.Code, tc.status, rr.Body.String())
 74→			}
 75→		})
 76→	}
 77→}
