 79→// TestPickupConfirmIntegration is an integration test that verifies the full
 80→// Preview + Confirm flow against a real database. Skipped unless DATABASE_URL is set.
 81→func TestPickupConfirmIntegration(t *testing.T) {
 82→	dbURL := strings.TrimSpace(os.Getenv("DATABASE_URL"))
 83→	if dbURL == "" {
 84→		t.Skip("DATABASE_URL not set")
 85→	}
 86→
 87→	ctx := context.Background()
 88→	schema := "it_" + randHex(t, 8)
 89→
 90→	// Create schema.
 91→	createCfg, err := pgx.ParseConfig(dbURL)
 92→	if err != nil {
 93→		t.Fatalf("parse DATABASE_URL: %v", err)
 94→	}
 95→	conn, err := pgx.ConnectConfig(ctx, createCfg)
 96→	if err != nil {
 97→		t.Fatalf("connect: %v", err)
 98→	}
 99→	if _, err := conn.Exec(ctx, `create schema `+schema); err != nil {
100→		_ = conn.Close(ctx)
101→		t.Fatalf("create schema: %v", err)
102→	}
103→	_ = conn.Close(ctx)
104→
105→	defer func() {
106→		cfg, err := pgx.ParseConfig(dbURL)
107→		if err != nil {
108→			return
109→		}
110→		c, err := pgx.ConnectConfig(context.Background(), cfg)
111→		if err != nil {
112→			return
113→		}
114→		_, _ = c.Exec(context.Background(), `drop schema if exists `+schema+` cascade`)
115→		_ = c.Close(context.Background())
116→	}()
117→
118→	// Run migrations.
119→	migCfg, err := pgx.ParseConfig(dbURL)
120→	if err != nil {
121→		t.Fatalf("parse: %v", err)
122→	}
123→	migCfg.RuntimeParams["search_path"] = schema + ",public"
124→	sqlDB := stdlib.OpenDB(*migCfg)
125→	sqlDB.SetMaxOpenConns(1)
126→	defer sqlDB.Close()
127→
128→	if err := goose.SetDialect("postgres"); err != nil {
129→		t.Fatalf("goose dialect: %v", err)
130→	}
131→	migrationsDir := filepath.Join("..", "..", "..", "migrations")
132→	if err := goose.Up(sqlDB, migrationsDir); err != nil {
133→		t.Fatalf("goose up: %v", err)
134→	}
135→
136→	poolCfg, err := pgxpool.ParseConfig(dbURL)
137→	if err != nil {
138→		t.Fatalf("pool parse: %v", err)
139→	}
140→	poolCfg.ConnConfig.RuntimeParams["search_path"] = schema + ",public"
141→	pool, err := pgxpool.NewWithConfig(ctx, poolCfg)
142→	if err != nil {
143→		t.Fatalf("pool: %v", err)
144→	}
145→	defer pool.Close()
146→
147→	// Arrange: user, store, location, window, product, offering, order.
148→	var sellerUserID, otherUserID, storeID, windowID, orderID, pickupCode string
149→
150→	if err := pool.QueryRow(ctx, `insert into users (email, role) values ('seller@example.com', 'seller') returning id::text`).Scan(&sellerUserID); err != nil {
151→		t.Fatalf("insert seller: %v", err)
152→	}
153→	if err := pool.QueryRow(ctx, `insert into users (email, role) values ('other@example.com', 'seller') returning id::text`).Scan(&otherUserID); err != nil {
154→		t.Fatalf("insert other user: %v", err)
155→	}
156→	if err := pool.QueryRow(ctx, `insert into stores (owner_user_id, name) values ($1::uuid, 'Test Farm') returning id::text`, sellerUserID).Scan(&storeID); err != nil {
157→		t.Fatalf("insert store: %v", err)
158→	}
159→
160→	var locID string
161→	if err := pool.QueryRow(ctx, `insert into pickup_locations (store_id, address1, city, region, postal_code, timezone) values ($1::uuid, '123 Main', 'Town', 'CA', '99999', 'UTC') returning id::text`, storeID).Scan(&locID); err != nil {
162→		t.Fatalf("insert location: %v", err)
163→	}
164→
165→	startAt := time.Now().UTC().Add(24 * time.Hour).Truncate(time.Second)
166→	if err := pool.QueryRow(ctx, `insert into pickup_windows (store_id, pickup_location_id, start_at, end_at, cutoff_at, status) values ($1::uuid, $2::uuid, $3, $4, $5, 'published') returning id::text`,
167→		storeID, locID, startAt, startAt.Add(2*time.Hour), startAt.Add(-2*time.Hour)).Scan(&windowID); err != nil {
168→		t.Fatalf("insert window: %v", err)
169→	}
170→
171→	var productID, offeringID string
172→	if err := pool.QueryRow(ctx, `insert into products (store_id, title, unit) values ($1::uuid, 'Apples', 'lb') returning id::text`, storeID).Scan(&productID); err != nil {
173→		t.Fatalf("insert product: %v", err)
